import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';

// Pages Import
import Home from './pages/Home';
import Services from './pages/Services';
import Registration from './pages/Registration';
import Login from './pages/Login'; 
import AdminDashboard from './pages/Admin'; 
import ClientDashboard from './pages/ClientDashboard';

// Bootstrap CSS
import 'bootstrap/dist/css/bootstrap.min.css';

function App() {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const loggedInUser = localStorage.getItem('clientUser');
    if (loggedInUser) {
      setUser(JSON.parse(loggedInUser));
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('clientUser');
    setUser(null);
    alert("Logged out successfully!");
    window.location.href = "/"; 
  };

  return (
    <Router>
      <div className="App d-flex flex-column min-vh-100">
        
        {/* --- NAVIGATION BAR START --- */}
        <nav className="navbar navbar-expand-lg navbar-dark bg-dark shadow sticky-top">
          <div className="container">
            {/* येथे नाव बदलले आहे: FreelanceHub ऐवजी Freelancer Marketplace */}
            <Link className="navbar-brand fw-bold fs-3" to="/">
              Freelancer<span className="text-primary"> Marketplace</span>
            </Link>
            
            <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarNav">
              <span className="navbar-toggler-icon"></span>
            </button>
            
            <div className="collapse navbar-collapse justify-content-end" id="navbarNav">
              <ul className="navbar-nav align-items-center">
                <li className="nav-item"><Link className="nav-link" to="/">Home</Link></li>
                <li className="nav-item"><Link className="nav-link" to="/services">Services</Link></li>
                <li className="nav-item"><Link className="nav-link text-info fw-bold" to="/client-dashboard">Client Dashboard</Link></li>
                <li className="nav-item"><Link className="nav-link text-warning fw-bold ms-lg-2" to="/admin">Admin Access</Link></li>
                
                {!user && (
                  <li className="nav-item ms-lg-3">
                    <Link className="nav-link fw-bold text-white" to="/login">Login</Link>
                  </li>
                )}

                <li className="nav-item ms-lg-2">
                  {user ? (
                    <button onClick={handleLogout} className="btn btn-danger px-4 shadow-sm fw-bold">Logout</button>
                  ) : (
                    <Link className="btn btn-primary px-4 shadow-sm fw-bold" to="/register">Hire Me</Link>
                  )}
                </li>
              </ul>
            </div>
          </div>
        </nav>
        {/* --- NAVIGATION BAR END --- */}

        <main className="flex-grow-1">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/services" element={<Services />} />
            <Route path="/register" element={<Registration />} />
            <Route path="/login" element={<Login />} />
            <Route path="/admin" element={<AdminDashboard />} />
            <Route path="/client-dashboard" element={<ClientDashboard />} />
          </Routes>
        </main>

        <footer className="bg-dark text-white py-4 text-center mt-auto border-top border-secondary">
          <div className="container">
            <p className="mb-0 opacity-75">
              © 2026 Freelancer Marketplace | Multi-Level Architecture (MLA) Project
            </p>
          </div>
        </footer>

      </div>
    </Router>
  );
}

export default App;
